const subscribers = [];

for (const item of $input.all()) {
  subscribers.push({
    json: {
      email_address: item.json["Email address"],
      status: "subscribed",
      merge_fields: {
        FNAME: item.json.Names.split(' ')[0] || '',
        LNAME: item.json.Names.split(' ').slice(1).join(' ') || '',
        PHONE: item.json["Phone Number"] || ''
      }
    }
  });
}

return subscribers;

